import React, { useRef } from 'react';
import { Canvas, useFrame } from '@react-three/fiber';
import { Float, MeshTransmissionMaterial, Environment, Stars } from '@react-three/drei';
import * as THREE from 'three';
import { ThemeMode } from '../types';

const FloatingLens = ({ position, scale, speed, rotationSpeed }: any) => {
  const meshRef = useRef<THREE.Mesh>(null);

  useFrame((state) => {
    if (!meshRef.current) return;
    const t = state.clock.getElapsedTime();
    meshRef.current.rotation.x = t * rotationSpeed;
    meshRef.current.rotation.y = t * rotationSpeed * 0.5;
    meshRef.current.position.y = position[1] + Math.sin(t * speed) * 0.2;
  });

  return (
    <Float floatIntensity={2} rotationIntensity={1}>
        <mesh ref={meshRef} position={position} scale={scale}>
        <torusGeometry args={[1, 0.3, 16, 100]} />
        <MeshTransmissionMaterial 
            backside
            backsideThickness={5}
            thickness={2}
            roughness={0}
            transmission={1}
            ior={1.5}
            chromaticAberration={0.4} // High chromatic aberration for that "lens" look
            anisotropy={0.5}
            distortion={0.5}
            distortionScale={0.5}
            temporalDistortion={0.1}
            color="#a7f3d0"
        />
        </mesh>
    </Float>
  );
};

const AbstractShape = ({ position, color }: any) => {
    return (
        <Float floatIntensity={1} rotationIntensity={0.5}>
            <mesh position={position}>
                <icosahedronGeometry args={[0.8, 0]} />
                <meshStandardMaterial 
                    color={color} 
                    roughness={0.1} 
                    metalness={0.8}
                    transparent
                    opacity={0.6}
                />
            </mesh>
        </Float>
    )
}

export const BackgroundScene: React.FC<{ theme: ThemeMode }> = ({ theme }) => {
  const isLight = theme === 'light';

  return (
    <div className="fixed inset-0 z-0 pointer-events-none transition-opacity duration-1000">
      <Canvas camera={{ position: [0, 0, 10], fov: 40 }} gl={{ alpha: true, antialias: true }}>
        <ambientLight intensity={isLight ? 1 : 0.4} />
        <spotLight position={[10, 10, 10]} angle={0.15} penumbra={1} intensity={1} />
        <pointLight position={[-10, -10, -10]} intensity={1} color={isLight ? "#3B82F6" : "#22D3EE"} />

        {/* Floating Glass Elements representing Lenses/Screens */}
        <FloatingLens position={[-3, 2, 0]} scale={1.2} speed={0.5} rotationSpeed={0.2} />
        <FloatingLens position={[4, -2, -2]} scale={1.5} speed={0.3} rotationSpeed={0.15} />

        <AbstractShape position={[0, 0, -5]} color={isLight ? "#D4AF37" : "#6D28D9"} />

        <Environment preset={isLight ? "studio" : "city"} />

        {!isLight && <Stars radius={100} depth={50} count={2000} factor={4} saturation={0} fade speed={1} />}
      </Canvas>
    </div>
  );
};

