                             <h3 className="text-2xl font-bold text-white mb-2">{project.title}</h3>
                             <p className="text-slate-300 text-sm opacity-0 group-hover:opacity-100 transition-opacity delay-100">{project.description}</p>
                        </div>

                        {/* Admin Overlays */}
                        {isAdmin && (
                            <div className="absolute top-4 right-4 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity z-10">
                                <button onClick={(e) => handleEdit(project, e)} className="p-2 bg-blue-500 text-white rounded-lg shadow-lg hover:scale-110 transition-transform"><Edit2 size={16} /></button>
                                <button onClick={(e) => handleDelete(project.id, e)} className="p-2 bg-red-500 text-white rounded-lg shadow-lg hover:scale-110 transition-transform"><Trash2 size={16} /></button>
