                        <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent pointer-events-none" />
                        <div className="absolute bottom-8 left-8 text-white pointer-events-none">
                             <span className="px-3 py-1 rounded-full bg-cyan-500 text-xs font-bold uppercase tracking-wider mb-2 inline-block">{selectedProject.category}</span>
                             <h2 className="text-4xl font-bold">{selectedProject.title}</h2>
