    if (!url) return false;
    return url.includes('.mp4') || url.includes('.webm') || url.startsWith('data:video');
  };

  // Admin Actions
  const handleDelete = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if(confirm('Delete this project?')) {
        setProjects(projects.filter(p => p.id !== id));
    }
  };

  const handleEdit = (project: Project, e: React.MouseEvent) => {
    e.stopPropagation();
    setEditForm(project);
    setIsEditing(true);
  };

  const handleAddNew = () => {
    setEditForm({ id: Date.now().toString(), title: '', category: 'Video', image: '', description: '' });
    setIsEditing(true);
  };

  const handleSave = () => {
    if (!editForm.title || !editForm.image) return;

    if (projects.find(p => p.id === editForm.id)) {
        setProjects(projects.map(p => p.id === editForm.id ? editForm as Project : p));
    } else {
        setProjects([editForm as Project, ...projects]);
    }
    setIsEditing(false);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setEditForm(prev => ({ ...prev, image: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  return (
    <section id="projects" className="py-24 relative z-10 min-h-screen">
      <div className="container mx-auto px-6">

        {/* Header & Filter */}
        <div className="flex flex-col md:flex-row justify-between items-center mb-12 gap-6">
